arguments.prompt:
You are working in /tmp/sv-0a0d057e53e44b349e26c8a7a153a927/ShipmentTracker which is a Blazor Web App with Interactive Auto Global mode and Individual auth.

The project structure is:
- ShipmentTracker/ (server project with Components/, Data/, Program.cs)
- ShipmentTracker.Client/ (WebAssembly project with Pages/, Layout/)

The app already has Identity auth scaffolded with ApplicationDbContext using SQLite.

Your task: Implement a shipment tracking system for a logistics company. Here's what to build:

## 1. Shared Model (in Client project since interactive components need it)

Create `ShipmentTracker.Client/Models/Shipment.cs`:
```csharp
namespace ShipmentTracker.Client.Models;

public class Shipment
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public string? CustomerEmail { get; set; }
    public string? Notes { get; set; }
}

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Delayed
}
```

## 2. Service Interface (in Client project)

Create `ShipmentTracker.Client/Services/IShipmentService.cs`:
```csharp
namespace ShipmentTracker.Client.Services;

using ShipmentTracker.Client.Models;

public interface IShipmentService
{
    Task<List<Shipment>> GetAllShipmentsAsync();
    Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber);
    Task<Shipment> CreateShipmentAsync(Shipment shipment);
    Task<Shipment> UpdateShipmentAsync(Shipment shipment);
}
```

## 3. Client-side implementation (HttpClient-based, in Client project)

Create `ShipmentTracker.Client/Services/ShipmentHttpService.cs`:
```csharp
using System.Net.Http.Json;
using ShipmentTracker.Client.Models;

namespace ShipmentTracker.Client.Services;

public class ShipmentHttpService(HttpClient http) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
        => await http.GetFromJsonAsync<List<Shipment>>("api/shipments") ?? [];

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var response = await http.GetAsync($"api/shipments/track/{trackingNumber}");
        if (!response.IsSuccessStatusCode) return null;
        return await response.Content.ReadFromJsonAsync<Shipment>();
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var response = await http.PostAsJsonAsync("api/shipments", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var response = await http.PutAsJsonAsync($"api/shipments/{shipment.Id}", shipment);
        response.EnsureSuccessStatusCode();
        return (await response.Content.ReadFromJsonAsync<Shipment>())!;
    }
}
```

## 4. Register HttpClient and service in Client Program.cs

Update `ShipmentTracker.Client/Program.cs` to:
```csharp
using Microsoft.AspNetCore.Components.WebAssembly.Hosting;
using ShipmentTracker.Client.Services;

var builder = WebAssemblyHostBuilder.CreateDefault(args);

builder.Services.AddAuthorizationCore();
builder.Services.AddCascadingAuthenticationState();
builder.Services.AddAuthenticationStateDeserialization();

builder.Services.AddHttpClient("ShipmentTracker.ServerAPI", client =>
    client.BaseAddress = new Uri(builder.HostEnvironment.BaseAddress));
builder.Services.AddScoped(sp => sp.GetRequiredService<IHttpClientFactory>().CreateClient("ShipmentTracker.ServerAPI"));
builder.Services.AddScoped<IShipmentService, ShipmentHttpService>();

await builder.Build().RunAsync();
```

## 5. Server-side Shipment entity & DbContext changes

Create `ShipmentTracker/Data/ShipmentEntity.cs`:
```csharp
using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public class ShipmentEntity
{
    public int Id { get; set; }
    [MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Origin { get; set; } = string.Empty;
    [MaxLength(200)]
    public string Destination { get; set; } = string.Empty;
    public int Status { get; set; }
    public DateTime CreatedDate { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    [MaxLength(256)]
    public string? CustomerEmail { get; set; }
    [MaxLength(500)]
    public string? Notes { get; set; }
}
```

Add a DbSet to the existing `ApplicationDbContext`. Find it at `ShipmentTracker/Data/ApplicationDbContext.cs` and add:
```csharp
public DbSet<ShipmentEntity> Shipments => Set<ShipmentEntity>();
```

## 6. Server-side service implementation

Create `ShipmentTracker/Services/ShipmentServerService.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;
using ShipmentTracker.Data;

namespace ShipmentTracker.Services;

public class ShipmentServerService(ApplicationDbContext db) : IShipmentService
{
    public async Task<List<Shipment>> GetAllShipmentsAsync()
    {
        return await db.Shipments
            .OrderByDescending(s => s.CreatedDate)
            .Select(s => ToModel(s))
            .ToListAsync();
    }

    public async Task<Shipment?> GetShipmentByTrackingNumberAsync(string trackingNumber)
    {
        var entity = await db.Shipments
            .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
        return entity is null ? null : ToModel(entity);
    }

    public async Task<Shipment> CreateShipmentAsync(Shipment shipment)
    {
        var entity = ToEntity(shipment);
        entity.TrackingNumber = GenerateTrackingNumber();
        entity.CreatedDate = DateTime.UtcNow;
        db.Shipments.Add(entity);
        await db.SaveChangesAsync();
        return ToModel(entity);
    }

    public async Task<Shipment> UpdateShipmentAsync(Shipment shipment)
    {
        var entity = await db.Shipments.FindAsync(shipment.Id)
            ?? throw new InvalidOperationException("Shipment not found");
        entity.Status = (int)shipment.Status;
        entity.Destination = shipment.Destination;
        entity.EstimatedDelivery = shipment.EstimatedDelivery;
        entity.Notes = shipment.Notes;
        await db.SaveChangesAsync();
        return ToModel(entity);
    }

    private static string GenerateTrackingNumber()
        => $"SHP-{DateTime.UtcNow:yyyyMMdd}-{Random.Shared.Next(1000, 9999)}";

    private static Shipment ToModel(ShipmentEntity e) => new()
    {
        Id = e.Id,
        TrackingNumber = e.TrackingNumber,
        Origin = e.Origin,
        Destination = e.Destination,
        Status = (ShipmentStatus)e.Status,
        CreatedDate = e.CreatedDate,
        EstimatedDelivery = e.EstimatedDelivery,
        CustomerEmail = e.CustomerEmail,
        Notes = e.Notes
    };

    private static ShipmentEntity ToEntity(Shipment s) => new()
    {
        Id = s.Id,
        TrackingNumber = s.TrackingNumber,
        Origin = s.Origin,
        Destination = s.Destination,
        Status = (int)s.Status,
        CreatedDate = s.CreatedDate,
        EstimatedDelivery = s.EstimatedDelivery,
        CustomerEmail = s.CustomerEmail,
        Notes = s.Notes
    };
}
```

## 7. API Endpoints

Create `ShipmentTracker/Endpoints/ShipmentEndpoints.cs`:
```csharp
using Microsoft.EntityFrameworkCore;
using ShipmentTracker.Client.Models;
using ShipmentTracker.Client.Services;

namespace ShipmentTracker.Endpoints;

public static class ShipmentEndpoints
{
    public static void MapShipmentEndpoints(this WebApplication app)
    {
        var group = app.MapGroup("api/shipments");

        group.MapGet("/", async (IShipmentService service) =>
            Results.Ok(await service.GetAllShipmentsAsync()))
            .RequireAuthorization();

        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, IShipmentService service) =>
        {
            var shipment = await service.GetShipmentByTrackingNumberAsync(trackingNumber);
            return shipment is null ? Results.NotFound() : Results.Ok(shipment);
        }).RequireAuthorization();

        group.MapPost("/", async (Shipment shipment, IShipmentService service) =>
        {
            var created = await service.CreateShipmentAsync(shipment);
            return Results.Created($"api/shipments/track/{created.TrackingNumber}", created);
        }).RequireAuthorization();

        group.MapPut("/{id}", async (int id, Shipment shipment, IShipmentService service) =>
        {
            shipment.Id = id;
            var updated = await service.UpdateShipmentAsync(shipment);
            return Results.Ok(updated);
        }).RequireAuthorization();
    }
}
```

## 8. Update Server Program.cs

Add to server Program.cs BEFORE `var app = builder.Build();`:
```csharp
builder.Services.AddScoped<IShipmentService, ShipmentServerService>();
```

Add the using statements at the top:
```csharp
using ShipmentTracker.Client.Services;
using ShipmentTracker.Services;
using ShipmentTracker.Endpoints;
```

Add BEFORE `app.Run();`:
```csharp
app.MapShipmentEndpoints();
```

## 9. Pages in Client project

Delete the existing template pages (Counter.razor and Weather.razor if they exist in ShipmentTracker.Client/Pages/).

### Dispatcher Dashboard - `ShipmentTracker.Client/Pages/Dashboard.razor`:
```razor
@page "/dashboard"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

@if (_loading)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>

    @if (_showCreate)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">Create New Shipment</h5>
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Origin" @bind="_newShipment.Origin" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Destination" @bind="_newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Customer Email" @bind="_newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-3">
                        <input type="date" class="form-control" @bind="_newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-2">
                    <button class="btn btn-success btn-sm" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary btn-sm" @onclick="() => _showCreate = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination..." @bind="_filter" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
