@page "/dashboard"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

@if (_loading)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>

    @if (_showCreate)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">Create New Shipment</h5>
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Origin" @bind="_newShipment.Origin" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Destination" @bind="_newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Customer Email" @bind="_newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-3">
                        <input type="date" class="form-control" @bind="_newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-2">
                    <button class="btn btn-success btn-sm" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary btn-sm" @onclick="() => _showCreate = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination..." @bind="_filter" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <select class="form-select form-select-sm" value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => UpdateShipment(shipment)">
                            Save
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment> _shipments = [];
    private bool _loading = true;
    private bool _showCreate;
    private string _filter = string.Empty;
    private Shipment _newShipment = new();

    private IEnumerable<Shipment> FilteredShipments => string.IsNullOrWhiteSpace(_filter)
        ? _shipments
        : _shipments.Where(s => s.Destination.Contains(_filter, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
        _loading = false;
    }

    private void ShowCreateForm()
    {
        _newShipment = new Shipment();
        _showCreate = true;
    }

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(_newShipment);
        _shipments.Insert(0, created);
        _showCreate = false;
    }

    private void UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
            shipment.Status = status;
    }

    private async Task UpdateShipment(Shipment shipment)
    {
        await ShipmentService.UpdateShipmentAsync(shipment);
    }
}

@page "/track"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Track Shipment</PageTitle>

<h2>Track Your Shipment</h2>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <input class="form-control" placeholder="Enter tracking number (e.g., SHP-20260525-1234)"
                   @bind="_trackingNumber" @onkeydown="HandleKeyDown" />
            <button class="btn btn-primary" @onclick="Search">Track</button>
        </div>
    </div>
</div>

@if (_searching)
{
    <p><em>Searching...</em></p>
}
else if (_searched && _shipment is null)
{
    <div class="alert alert-warning">No shipment found with that tracking number.</div>
}
else if (_shipment is not null)
{
    <div class="card">
        <div class="card-header">
            <strong>@_shipment.TrackingNumber</strong>
        </div>
        <div class="card-body">
            <div class="row">
                <div class="col-md-6">
                    <dl>
                        <dt>Origin</dt>
                        <dd>@_shipment.Origin</dd>
                        <dt>Destination</dt>
                        <dd>@_shipment.Destination</dd>
                        <dt>Status</dt>
                        <dd><span class="badge @GetStatusBadgeClass(_shipment.Status)">@_shipment.Status</span></dd>
                    </dl>
                </div>
                <div class="col-md-6">
                    <dl>
                        <dt>Shipped Date</dt>
                        <dd>@_shipment.CreatedDate.ToString("MMMM dd, yyyy")</dd>
                        <dt>Estimated Delivery</dt>
                        <dd>@(_shipment.EstimatedDelivery?.ToString("MMMM dd, yyyy") ?? "TBD")</dd>
                    </dl>
                </div>
            </div>

            <h5 class="mt-3">Shipment Progress</h5>
            <div class="progress" style="height: 30px;">
                <div class="progress-bar @GetStatusBadgeClass(_shipment.Status)"
                     role="progressbar"
                     style="width: @(GetProgressPercent(_shipment.Status))%">
                    @_shipment.Status
                </div>
            </div>
        </div>
    </div>
}

@code {
    private string _trackingNumber = string.Empty;
    private Shipment? _shipment;
    private bool _searching;
    private bool _searched;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(_trackingNumber)) return;
        _searching = true;
        _searched = false;
        _shipment = await ShipmentService.GetShipmentByTrackingNumberAsync(_trackingNumber.Trim());
        _searching = false;
        _searched = true;
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter") await Search();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Delayed => "bg-danger",
        _ => "bg-secondary"
    };

    private static int GetProgressPercent(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => 10,
        ShipmentStatus.PickedUp => 25,
        ShipmentStatus.InTransit => 50,
        ShipmentStatus.OutForDelivery => 75,
        ShipmentStatus.Delivered => 100,
        ShipmentStatus.Delayed => 50,
        _ => 0
    };
}

@page "/dashboard"
@using ShipmentTracker.Client.Models
@using ShipmentTracker.Client.Services
@attribute [Authorize]
@inject IShipmentService ShipmentService

<PageTitle>Dispatcher Dashboard</PageTitle>

<h2>Shipment Dashboard</h2>

@if (_loading)
{
    <p><em>Loading shipments...</em></p>
}
else
{
    <div class="mb-3">
        <button class="btn btn-primary" @onclick="ShowCreateForm">+ New Shipment</button>
    </div>

    @if (_showCreate)
    {
        <div class="card mb-3">
            <div class="card-body">
                <h5 class="card-title">Create New Shipment</h5>
                <div class="row g-2">
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Origin" @bind="_newShipment.Origin" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Destination" @bind="_newShipment.Destination" />
                    </div>
                    <div class="col-md-3">
                        <input class="form-control" placeholder="Customer Email" @bind="_newShipment.CustomerEmail" />
                    </div>
                    <div class="col-md-3">
                        <input type="date" class="form-control" @bind="_newShipment.EstimatedDelivery" />
                    </div>
                </div>
                <div class="mt-2">
                    <button class="btn btn-success btn-sm" @onclick="CreateShipment">Create</button>
                    <button class="btn btn-secondary btn-sm" @onclick="() => _showCreate = false">Cancel</button>
                </div>
            </div>
        </div>
    }

    <div class="mb-3">
        <input class="form-control" placeholder="Filter by destination..." @bind="_filter" @bind:event="oninput" />
    </div>

    <table class="table table-striped">
        <thead>
            <tr>
                <th>Tracking #</th>
                <th>Origin</th>
                <th>Destination</th>
                <th>Status</th>
                <th>Est. Delivery</th>
                <th>Actions</th>
            </tr>
        </thead>
        <tbody>
            @foreach (var shipment in FilteredShipments)
            {
                <tr>
                    <td>@shipment.TrackingNumber</td>
                    <td>@shipment.Origin</td>
                    <td>@shipment.Destination</td>
                    <td>
                        <select class="form-select form-select-sm" value="@shipment.Status"
                                @onchange="e => UpdateStatus(shipment, e)">
                            @foreach (var status in Enum.GetValues<ShipmentStatus>())
                            {
                                <option value="@status">@status</option>
                            }
                        </select>
                    </td>
                    <td>@shipment.EstimatedDelivery?.ToString("yyyy-MM-dd")</td>
                    <td>
                        <button class="btn btn-sm btn-outline-primary" @onclick="() => UpdateShipment(shipment)">
                            Save
                        </button>
                    </td>
                </tr>
            }
        </tbody>
    </table>
}

@code {
    private List<Shipment> _shipments = [];
    private bool _loading = true;
    private bool _showCreate;
    private string _filter = string.Empty;
    private Shipment _newShipment = new();

    private IEnumerable<Shipment> FilteredShipments => string.IsNullOrWhiteSpace(_filter)
        ? _shipments
        : _shipments.Where(s => s.Destination.Contains(_filter, StringComparison.OrdinalIgnoreCase));

    protected override async Task OnInitializedAsync()
    {
        _shipments = await ShipmentService.GetAllShipmentsAsync();
        _loading = false;
    }

    private void ShowCreateForm()
    {
        _newShipment = new Shipment();
        _showCreate = true;
    }

    private async Task CreateShipment()
    {
        var created = await ShipmentService.CreateShipmentAsync(_newShipment);
        _shipments.Insert(0, created);
        _showCreate = false;
    }

    private void UpdateStatus(Shipment shipment, ChangeEventArgs e)
    {
        if (Enum.TryParse<ShipmentStatus>(e.Value?.ToString(), out var status))
            shipment.Status = status;
    }

    private async Task UpdateShipment(Shipment shipment)
    {
        await ShipmentService.UpdateShipmentAsync(shipment);
    }
}

